                  label:'Restore Backup',icon:'restore',
                  headers:[], getRows:()=>[],
                  fmts:['restore'],
                  restoreFn:()=>importJSON(data=>{if(window.confirm('Replace ALL data with backup?')){save({...db,...data});toast('Data restored');}}),
